// Home.jsx — No backend logic, only navigation UI
import React from "react";
import { useNavigate } from "react-router-dom";
import "./Home.css";

export default function Home({ employee }) {
  const navigate = useNavigate();

  return (
    <div className="home-container" style={outer}>
      <img src="/logo.png" alt="PRASA Logo" className="home-logo" style={logo} />

      <div style={title}>PRASA Infocom & Power Solutions Pvt. Ltd.</div>

      <div style={subtitle}>
        Welcome to PRASA Employee Portal{employee?.name ? `, ${employee.name}` : ""}
      </div>

      <div style={btnWrapper}>
        <button className="home-btn" onClick={() => navigate("/profile")} style={btn}>
          Profile
        </button>

        <button className="home-btn" onClick={() => navigate("/settings")} style={btn}>
          Settings
        </button>
      </div>
    </div>
  );
}

const outer = {
  minHeight: "100vh",
  background: "linear-gradient(180deg, #e8f5e9 0%, #fff 80%)",
  display: "flex",
  flexDirection: "column",
  justifyContent: "center",
  alignItems: "center",
  padding: 24,
};
const logo = { width: 110, height: 110, background: "#fff", borderRadius: 22, padding: 12, boxShadow: "0 4px 18px rgba(0,0,0,0.12)", marginBottom: 18 };
const title = { fontSize: 20, fontWeight: 700, color: "#0f9d58", textAlign: "center" };
const subtitle = { fontSize: 16, color: "#424242", marginTop: 8, marginBottom: 24, textAlign: "center" };
const btnWrapper = { width: "80%", maxWidth: 320 };
const btn = { backgroundColor: "#0f9d58", padding: 14, borderRadius: 18, marginBottom: 16, fontWeight: 600 };
